import{_ as a,c as t,o as s,a1 as r}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"5 分钟上手 Superpowers：安装、验证与第一个命令 | Superpowers 教程","description":"在 5 分钟内安装并体验 Superpowers 的核心功能，包括安装、验证和第一个命令的使用。本教程让你快速了解 Superpowers 如何提升 AI 编码代理的开发效率。","frontmatter":{"title":"5 分钟上手 Superpowers：安装、验证与第一个命令 | Superpowers 教程","sidebarTitle":"5 分钟跑起来","subtitle":"快速开始：5 分钟上手 Superpowers","description":"在 5 分钟内安装并体验 Superpowers 的核心功能，包括安装、验证和第一个命令的使用。本教程让你快速了解 Superpowers 如何提升 AI 编码代理的开发效率。","tags":["快速开始","入门","安装"],"order":20},"headers":[],"relativePath":"zh/obra/superpowers/start/quick-start/index.md","filePath":"zh/obra/superpowers/start/quick-start/index.md"}'),i={name:"zh/obra/superpowers/start/quick-start/index.md"};function o(l,e,p,n,d,h){return s(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="快速开始-5-分钟上手-superpowers" tabindex="-1">快速开始：5 分钟上手 Superpowers <a class="header-anchor" href="#快速开始-5-分钟上手-superpowers" aria-label="Permalink to &quot;快速开始：5 分钟上手 Superpowers&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>在 5 分钟内完成 Superpowers 安装</li><li>验证插件正确加载</li><li>使用第一个核心命令体验 AI 代理的新能力</li></ul><hr><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>用 AI 写代码时，你是不是遇到过这些问题：</p><ul><li>AI 直接跳过设计就开始写代码，改来改去还是不对</li><li>写完一堆代码才发现逻辑错误，浪费半小时</li><li>没有测试，上线后才发现 Bug</li><li>AI 偷懒跳过 TDD，代码质量不稳定</li></ul><p><strong>Superpowers 专治这些问题</strong>——它不是给&quot;更聪明的 AI&quot;用的，是给&quot;听话的 AI&quot;用的。通过强制的工作流，让 AI 遵循最佳实践。</p><hr><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><p>任何时候你要用 AI 写代码：</p><ul><li>✅ 构建新功能</li><li>✅ 修复 Bug</li><li>✅ 重构代码</li><li>✅ 编写测试</li></ul><p>Superpowers 会自动检查任务类型，触发对应的技能工作流。</p><hr><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><h3 id="平台选择" tabindex="-1">平台选择 <a class="header-anchor" href="#平台选择" aria-label="Permalink to &quot;平台选择&quot;">​</a></h3><p>Superpowers 支持三大 AI 编码平台：</p><table tabindex="0"><thead><tr><th>平台</th><th>安装难度</th><th>推荐度</th></tr></thead><tbody><tr><td>Claude Code</td><td>⭐ 最简单</td><td>✅ 推荐新手</td></tr><tr><td>OpenCode</td><td>⭐⭐⭐ 中等</td><td>高级用户</td></tr><tr><td>Codex</td><td>⭐⭐⭐ 复杂</td><td>有 CLI 经验</td></tr></tbody></table><p><strong>本教程使用 Claude Code</strong>，因为它有内置插件市场，安装最快。</p><h3 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h3><ul><li>已安装 <a href="https://claude.ai/code" target="_blank" rel="noreferrer">Claude Code</a></li><li>有 GitHub 账号（用于插件市场）</li><li>基本的终端使用能力</li></ul><hr><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Superpowers 是什么？</p><p><strong>简单说</strong>：一套&quot;强制最佳实践&quot;的技能包。</p><p><strong>工作方式</strong>：在你让 AI 写代码前，它<strong>不会</strong>直接开写，而是：</p><ol><li><strong>先问你问题</strong>（brainstorming）——搞清楚你要做什么</li><li><strong>再写计划</strong>（writing-plans）——把任务拆成 2-5 分钟的小块</li><li><strong>用 TDD 开发</strong>（test-driven-development）——先写测试，再写代码</li><li><strong>代码审查</strong>（requesting-code-review）——每步都检查质量</li></ol><p><strong>这不是建议，是强制规则</strong>——技能会自动触发，AI 必须遵守。</p><hr><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-注册插件市场" tabindex="-1">第 1 步：注册插件市场 <a class="header-anchor" href="#第-1-步-注册插件市场" aria-label="Permalink to &quot;第 1 步：注册插件市场&quot;">​</a></h3><p>打开 Claude Code，输入：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> obra/superpowers-marketplace</span></span></code></pre></div><p><strong>为什么</strong></p><p>注册插件市场，让 Claude Code 知道去哪里找 Superpowers 插件。</p><p><strong>你应该看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Successfully added marketplace: obra/superpowers-marketplace</span></span></code></pre></div><hr><h3 id="第-2-步-安装-superpowers-插件" tabindex="-1">第 2 步：安装 Superpowers 插件 <a class="header-anchor" href="#第-2-步-安装-superpowers-插件" aria-label="Permalink to &quot;第 2 步：安装 Superpowers 插件&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> superpowers@superpowers-marketplace</span></span></code></pre></div><p><strong>为什么</strong></p><p>从刚才注册的市场下载并安装 Superpowers 插件。</p><p><strong>你应该看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>📦 Installing superpowers from superpowers-marketplace...</span></span>
<span class="line"><span>✅ Successfully installed superpowers</span></span></code></pre></div><hr><h3 id="第-3-步-验证安装" tabindex="-1">第 3 步：验证安装 <a class="header-anchor" href="#第-3-步-验证安装" aria-label="Permalink to &quot;第 3 步：验证安装&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/help</span></span></code></pre></div><p><strong>为什么</strong></p><p>检查 Superpowers 的命令是否正确加载。</p><p><strong>你应该看到</strong>以下命令：</p><table tabindex="0"><thead><tr><th>命令</th><th>功能</th></tr></thead><tbody><tr><td><code>/superpowers:brainstorm</code></td><td>交互式设计优化</td></tr><tr><td><code>/superpowers:write-plan</code></td><td>创建实施计划</td></tr><tr><td><code>/superpowers:execute-plan</code></td><td>批量执行计划</td></tr></tbody></table><p>如果看到这三个命令，说明安装成功！</p><hr><h3 id="第-4-步-体验第一个命令" tabindex="-1">第 4 步：体验第一个命令 <a class="header-anchor" href="#第-4-步-体验第一个命令" aria-label="Permalink to &quot;第 4 步：体验第一个命令&quot;">​</a></h3><p>现在试一下最核心的功能——让 AI 在写代码前先跟你聊清楚需求。</p><p>输入：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/superpowers:brainstorm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 我要给博客添加一个评论功能</span></span></code></pre></div><p><strong>为什么</strong></p><p>触发 brainstorming 技能，让 AI 先询问需求，而不是直接写代码。</p><p><strong>你会看到</strong>：</p><ol><li>AI 不会直接写代码</li><li>AI 会问你问题（比如：&quot;评论需要支持什么功能？需要登录吗？要不要点赞？&quot;）</li><li>你回答后，AI 会分段展示设计（每次 200-300 字，方便你消化）</li><li>设计确认后，AI 会把设计文档保存到 <code>docs/plans/</code> 目录</li></ol><p>这就是 Superpowers 的核心——<strong>先聊清楚，再写代码</strong>。</p><hr><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>确认以下检查点都通过：</p><ul><li>[ ] <code>/help</code> 能看到 <code>/superpowers:brainstorm</code> 等三个命令</li><li>[ ] <code>/superpowers:brainstorm</code> 命令能触发（AI 会先问问题，不是直接写代码）</li><li>[ ] AI 不会跳过设计直接开始编码</li></ul><p>如果以上都 OK，恭喜你已经完成了 Superpowers 的快速上手！</p><hr><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="命令不出现" tabindex="-1">命令不出现 <a class="header-anchor" href="#命令不出现" aria-label="Permalink to &quot;命令不出现&quot;">​</a></h3><p><strong>症状</strong>：<code>/help</code> 里看不到 Superpowers 命令</p><p><strong>解决</strong>：</p><ol><li>确认你输入的是 <code>/superpowers:brainstorm</code>（冒号不是空格）</li><li>尝试重启 Claude Code</li><li>重新执行安装步骤</li></ol><h3 id="ai-还是直接写代码" tabindex="-1">AI 还是直接写代码 <a class="header-anchor" href="#ai-还是直接写代码" aria-label="Permalink to &quot;AI 还是直接写代码&quot;">​</a></h3><p><strong>症状</strong>：使用 <code>/superpowers:brainstorm</code> 后，AI 直接开始写代码</p><p><strong>解决</strong>：</p><ul><li>这可能是因为你的问题太简单，AI 认为&quot;不需要设计&quot;</li><li>试试更复杂的任务（比如：&quot;重构用户认证系统，添加双因素认证&quot;）</li><li>确保安装了最新版本：<code>/plugin update superpowers</code></li></ul><hr><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>5 分钟内你完成了：</p><ol><li>✅ 安装 Superpowers 插件</li><li>✅ 验证命令正确加载</li><li>✅ 体验第一个核心功能（brainstorming）</li></ol><p><strong>核心收获</strong>：</p><ul><li>Superpowers 不是&quot;更聪明的 AI&quot;，是&quot;听话的 AI&quot;</li><li>它通过强制工作流（设计→计划→TDD→审查）保证代码质量</li><li>技能会自动触发，你不需要手动选择</li></ul><hr><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../installation/">安装指南</a></strong>。</p><p>你会学到：</p><ul><li>三大平台的完整安装步骤</li><li>OpenCode 和 Codex 的手动配置</li><li>详细的问题排查方法</li></ul></blockquote>`,86)])])}const g=a(i,[["render",o]]);export{c as __pageData,g as default};
